import{_ as t,c as o,a0 as d,o as a}from"./chunks/framework.B6JXc2q-.js";const u=JSON.parse('{"title":"播放器权威状态快照规范（Player State Projection Spec）","description":"","frontmatter":{},"headers":[],"relativePath":"spec/player_state_projection_spec.md","filePath":"spec/player_state_projection_spec.md"}'),c={name:"spec/player_state_projection_spec.md"};function i(r,e,l,s,n,h){return a(),o("div",null,e[0]||(e[0]=[d('<h1 id="播放器权威状态快照规范-player-state-projection-spec" tabindex="-1">播放器权威状态快照规范（Player State Projection Spec） <a class="header-anchor" href="#播放器权威状态快照规范-player-state-projection-spec" aria-label="Permalink to &quot;播放器权威状态快照规范（Player State Projection Spec）&quot;">​</a></h1><p>版本：v1.0 状态：正式规范 最后更新：2026-03-22 适用范围：<code>GET /api/v1/player/state</code>、未来的 <code>GET /api/v1/player/stream</code>（SSE）、PlaybackCoordinator / PlaybackFacade、WebUI 状态消费</p><hr><h2 id="_1-文档定位" tabindex="-1">1. 文档定位 <a class="header-anchor" href="#_1-文档定位" aria-label="Permalink to &quot;1. 文档定位&quot;">​</a></h2><p>本文档定义 XiaoMusic 播放器&quot;权威播放状态快照&quot;（Player State Projection）的结构、字段语义与消费约束。</p><p>本文档是以下内容的共同上位规范：</p><ul><li><code>GET /api/v1/player/state</code> 的响应数据结构与语义</li><li>未来 <code>GET /api/v1/player/stream</code> SSE 事件中 <code>data</code> 的状态结构与语义</li><li>PlaybackCoordinator 与 PlaybackFacade 对外暴露状态的约束边界</li><li>WebUI、Home Assistant、第三方调用方消费播放状态的合法边界</li></ul><p>本文档做出以下强制约束：</p><ol><li><strong>所有对外状态输出必须共享同一套状态投影逻辑。</strong> HTTP 状态查询与 SSE 状态推送不得分别维护独立的状态拼装逻辑；两者必须基于同一个状态快照构建器生成。</li><li><strong>前端不得以本地启发式逻辑（heuristic）或轮询补偿逻辑作为播放真相来源。</strong> 服务端投影是唯一权威来源，前端是消费者，不是裁决者。</li><li><strong>本文档所定义的正式字段语义，优先于任何现有实现行为。</strong> 若实现与本规范冲突，应判定为实现不符合规范，而非修改规范迁就实现。</li></ol><hr><h2 id="_2-背景与问题背景" tabindex="-1">2. 背景与问题背景 <a class="header-anchor" href="#_2-背景与问题背景" aria-label="Permalink to &quot;2. 背景与问题背景&quot;">​</a></h2><p>当前 XiaoMusic 前端存在以下已知问题，均由&quot;后端未提供单一权威状态投影、前端不得不自行猜测播放真相&quot;所导致：</p><ul><li><strong>未知歌曲问题</strong>：切歌瞬间后端返回空标题，前端无法区分&quot;真正的未知曲目&quot;与&quot;切歌过渡中的瞬态空值&quot;，导致 UI 短暂显示&quot;未知歌曲&quot;。</li><li><strong>进度条闪烁</strong>：旧 revision 或延迟到达的响应覆盖了更新的状态，导致进度条回退闪烁。</li><li><strong>选中项错位</strong>：前端依赖 <code>cur_music</code> 文本在歌单中定位当前曲目，同名歌曲或列表序号变化时导致选中项错误对齐。</li><li><strong>自动切歌不稳定</strong>：前端无法可靠判断&quot;切歌已完成&quot;与&quot;仍在切歌中&quot;，导致切歌确认逻辑依赖超时猜测。</li><li><strong>旧状态回写</strong>：慢请求、乱序响应或页面恢复时，旧状态被写回 UI，覆盖更新的播放状态。</li></ul><p>本规范通过定义统一状态快照模型，从根本上为上述问题提供解决基础。</p><hr><h2 id="_3-适用范围" tabindex="-1">3. 适用范围 <a class="header-anchor" href="#_3-适用范围" aria-label="Permalink to &quot;3. 适用范围&quot;">​</a></h2><p>本规范适用于：</p><ul><li>后端：任何构建并对外暴露播放器状态的模块，包括但不限于 API 路由层、PlaybackCoordinator、PlaybackFacade。</li><li>前端：WebUI 中所有消费 <code>GET /api/v1/player/state</code> 或未来 SSE 流的代码路径。</li><li>测试与验收：所有涉及播放器状态一致性、切歌确认、进度同步的验收用例。</li></ul><hr><h2 id="_4-设计原则" tabindex="-1">4. 设计原则 <a class="header-anchor" href="#_4-设计原则" aria-label="Permalink to &quot;4. 设计原则&quot;">​</a></h2><p>本规范遵循以下设计原则。所有实现与消费行为必须与这些原则保持一致。</p><h3 id="_4-1-单一权威状态来源" tabindex="-1">4.1 单一权威状态来源 <a class="header-anchor" href="#_4-1-单一权威状态来源" aria-label="Permalink to &quot;4.1 单一权威状态来源&quot;">​</a></h3><p>播放器的权威状态由服务端唯一决定。服务端的状态快照是唯一合法的&quot;当前播放真相&quot;，任何前端本地推算结果均不得凌驾于服务端快照之上。</p><h3 id="_4-2-可排序、可去乱序" tabindex="-1">4.2 可排序、可去乱序 <a class="header-anchor" href="#_4-2-可排序、可去乱序" aria-label="Permalink to &quot;4.2 可排序、可去乱序&quot;">​</a></h3><p>状态快照必须携带单调递增的版本号（<code>revision</code>），使消费方能够在多路响应同时到达时，安全地丢弃过期状态，始终只应用最新状态。</p><h3 id="_4-3-可区分-切歌中-与-未知曲目" tabindex="-1">4.3 可区分&quot;切歌中&quot;与&quot;未知曲目&quot; <a class="header-anchor" href="#_4-3-可区分-切歌中-与-未知曲目" aria-label="Permalink to &quot;4.3 可区分&quot;切歌中&quot;与&quot;未知曲目&quot;&quot;">​</a></h3><p>&quot;切歌中&quot;是一个明确的传输状态（<code>transport_state</code>），不得通过清空 <code>track.title</code> 或返回空值来隐式表达。消费方必须能从 <code>transport_state</code> 字段直接判断当前是否处于切歌过渡中。</p><h3 id="_4-4-曲目身份的稳定标识" tabindex="-1">4.4 曲目身份的稳定标识 <a class="header-anchor" href="#_4-4-曲目身份的稳定标识" aria-label="Permalink to &quot;4.4 曲目身份的稳定标识&quot;">​</a></h3><p>当前曲目必须有稳定的身份标识（<code>track.id</code>），不得仅靠 <code>track.title</code> 文本充当身份依据。<code>track.id</code> 在曲目切换时必须发生变化，在同一曲目的暂停/恢复过程中必须保持稳定。</p><h3 id="_4-5-支持前端平滑渲染-但不授权前端定义播放真相" tabindex="-1">4.5 支持前端平滑渲染，但不授权前端定义播放真相 <a class="header-anchor" href="#_4-5-支持前端平滑渲染-但不授权前端定义播放真相" aria-label="Permalink to &quot;4.5 支持前端平滑渲染，但不授权前端定义播放真相&quot;">​</a></h3><p>前端可以在两次状态更新之间做短时视觉插值（例如进度条补帧），但这仅是展示层平滑处理，不得被视为对播放真相的重新定义。一旦收到更高 <code>revision</code> 的服务端状态，前端必须立即以服务端状态为准，不得保留本地插值结果继续渲染。</p><h3 id="_4-6-命令流与状态流解耦" tabindex="-1">4.6 命令流与状态流解耦 <a class="header-anchor" href="#_4-6-命令流与状态流解耦" aria-label="Permalink to &quot;4.6 命令流与状态流解耦&quot;">​</a></h3><p>播放控制命令（通过 <code>POST /api/v1/play</code>、<code>POST /api/v1/control/*</code> 等接口发出）与播放状态观测（通过 <code>GET /api/v1/player/state</code> 或 SSE 获取）是相互独立的通道。前端不得依赖命令响应体中的状态字段推断当前播放状态，正式播放状态只能通过状态查询通道获取。</p><hr><h2 id="_5-权威播放状态快照模型" tabindex="-1">5. 权威播放状态快照模型 <a class="header-anchor" href="#_5-权威播放状态快照模型" aria-label="Permalink to &quot;5. 权威播放状态快照模型&quot;">​</a></h2><p>本节定义权威播放状态快照（以下简称&quot;状态快照&quot;）的字段模型。所有对外状态输出必须与本节定义保持一致。</p><h3 id="_5-1-顶层结构" tabindex="-1">5.1 顶层结构 <a class="header-anchor" href="#_5-1-顶层结构" aria-label="Permalink to &quot;5.1 顶层结构&quot;">​</a></h3><p>状态快照是一个 JSON 对象，包含以下字段分组：</p><ul><li>顶层身份字段</li><li>播放传输状态</li><li>曲目对象（<code>track</code>）</li><li>上下文信息（<code>context</code>）</li><li>进度与时长</li></ul><h3 id="_5-2-顶层身份字段" tabindex="-1">5.2 顶层身份字段 <a class="header-anchor" href="#_5-2-顶层身份字段" aria-label="Permalink to &quot;5.2 顶层身份字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必须存在</th><th>说明</th></tr></thead><tbody><tr><td><code>device_id</code></td><td><code>string</code></td><td>是</td><td>当前状态所属设备的唯一标识，非空字符串</td></tr><tr><td><code>revision</code></td><td><code>integer</code></td><td>是</td><td>状态版本号，单设备维度、单调递增，详见第 6 节</td></tr><tr><td><code>play_session_id</code></td><td><code>string</code></td><td>是</td><td>当前播放会话的唯一标识，详见第 7 节</td></tr></tbody></table><p><code>device_id</code> 必须与请求参数中的设备 ID 一致，不得返回其他设备的快照。</p><h3 id="_5-3-播放传输状态-transport-state" tabindex="-1">5.3 播放传输状态（<code>transport_state</code>） <a class="header-anchor" href="#_5-3-播放传输状态-transport-state" aria-label="Permalink to &quot;5.3 播放传输状态（`transport_state`）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必须存在</th><th>说明</th></tr></thead><tbody><tr><td><code>transport_state</code></td><td><code>string</code></td><td>是</td><td>播放器当前传输状态，必须属于第 8 节定义的枚举值</td></tr></tbody></table><p><code>transport_state</code> 是整个状态快照中语义优先级最高的字段。消费方在解析状态快照时，必须首先读取 <code>transport_state</code>，再结合其他字段做展示决策。</p><h3 id="_5-4-曲目对象-track" tabindex="-1">5.4 曲目对象（<code>track</code>） <a class="header-anchor" href="#_5-4-曲目对象-track" aria-label="Permalink to &quot;5.4 曲目对象（`track`）&quot;">​</a></h3><p><code>track</code> 是描述当前曲目身份的对象。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必须存在</th><th>说明</th></tr></thead><tbody><tr><td><code>track</code></td><td><code>object | null</code></td><td>是</td><td>当前曲目信息；<code>transport_state</code> 为 <code>idle</code> 或 <code>stopped</code> 时可为 <code>null</code></td></tr><tr><td><code>track.id</code></td><td><code>string</code></td><td>是（若 <code>track</code> 非空）</td><td>当前曲目的稳定身份标识，详见第 9 节</td></tr><tr><td><code>track.title</code></td><td><code>string</code></td><td>是（若 <code>track</code> 非空）</td><td>当前曲目的展示标题</td></tr></tbody></table><p>以下字段在 <code>track</code> 非空时可以包含，但消费方不得强依赖其存在：</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>track.artist</code></td><td><code>string</code></td><td>曲目艺术家</td></tr><tr><td><code>track.album</code></td><td><code>string</code></td><td>曲目所属专辑</td></tr><tr><td><code>track.source</code></td><td><code>string</code></td><td>曲目来源标识（如 <code>local_library</code>、<code>jellyfin</code>、<code>site_media</code>、<code>direct_url</code>）</td></tr></tbody></table><p>重要约束：</p><ul><li><strong><code>track.id</code> 是当前曲目的稳定身份标识。</strong> UI 同步、去重、切歌判断必须优先依赖 <code>track.id</code>，而不是 <code>track.title</code>。</li><li><code>track.title</code> 可为空字符串，表示标题信息尚未解析完成，但这不意味着曲目身份未知。<code>track.id</code> 仍应在此时保持稳定。</li><li>当 <code>transport_state</code> 为 <code>switching</code> 或 <code>starting</code> 时，<code>track</code> 可以携带即将播放的曲目信息，也可以为 <code>null</code>，但不得通过 <code>track</code> 置空来隐式表达&quot;切歌中&quot;语义。切歌中的语义必须由 <code>transport_state</code> 承载。</li></ul><h3 id="_5-5-上下文信息-context" tabindex="-1">5.5 上下文信息（<code>context</code>） <a class="header-anchor" href="#_5-5-上下文信息-context" aria-label="Permalink to &quot;5.5 上下文信息（`context`）&quot;">​</a></h3><p><code>context</code> 描述当前播放所属的上下文（例如歌单）及曲目在其中的位置。</p><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必须存在</th><th>说明</th></tr></thead><tbody><tr><td><code>context</code></td><td><code>object | null</code></td><td>是</td><td>播放上下文；若无上下文则为 <code>null</code></td></tr><tr><td><code>context.id</code></td><td><code>string</code></td><td>是（若 <code>context</code> 非空）</td><td>当前播放上下文的唯一标识（如歌单 ID）</td></tr><tr><td><code>context.name</code></td><td><code>string</code></td><td>是（若 <code>context</code> 非空）</td><td>当前播放上下文的展示名称</td></tr><tr><td><code>context.current_index</code></td><td><code>integer | null</code></td><td>是（若 <code>context</code> 非空）</td><td>当前曲目在上下文中的位置索引（从 0 开始），无法确定时为 <code>null</code></td></tr></tbody></table><p>约束说明：</p><ul><li><code>context.id</code> 与 <code>context.name</code> 分别承载上下文的身份与展示，消费方应使用 <code>context.id</code> 做逻辑判断，使用 <code>context.name</code> 做展示。</li><li><code>context.current_index</code> 仅表示当前曲目在当前上下文中的位置，不表示全局队列位置。消费方不得将其作为跨上下文的全局索引使用。</li><li><code>context</code> 为 <code>null</code> 表示当前播放不属于任何已知上下文（例如直接播放单个 URL），这是合法状态。消费方不得因 <code>context</code> 为 <code>null</code> 而推断播放出错。</li></ul><h3 id="_5-6-进度与时长" tabindex="-1">5.6 进度与时长 <a class="header-anchor" href="#_5-6-进度与时长" aria-label="Permalink to &quot;5.6 进度与时长&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>类型</th><th>必须存在</th><th>说明</th></tr></thead><tbody><tr><td><code>position_ms</code></td><td><code>integer</code></td><td>是</td><td>当前播放位置，单位：毫秒；<code>transport_state</code> 为 <code>idle</code> 或 <code>stopped</code> 时应为 <code>0</code></td></tr><tr><td><code>duration_ms</code></td><td><code>integer</code></td><td>是</td><td>当前曲目总时长，单位：毫秒；未知时为 <code>0</code></td></tr><tr><td><code>snapshot_at_ms</code></td><td><code>integer</code></td><td>是</td><td>本次快照生成时的服务端时间戳，单位：毫秒（Unix 时间戳）</td></tr></tbody></table><p>约束说明：</p><ul><li><code>position_ms</code> 是服务端在 <code>snapshot_at_ms</code> 时刻观测到的播放位置，是状态观测值，不是前端自行承诺的真值。</li><li>前端可以在两次快照之间，以 <code>snapshot_at_ms</code> 为基准、以本地时钟为参考做短时进度插值，使进度条展示更平滑。但一旦收到更高 <code>revision</code> 的新快照，必须立即以新快照的 <code>position_ms</code> 为准，放弃本地插值结果。</li><li>前端不得将本地插值结果写回或上报为&quot;真实播放位置&quot;。</li><li><code>duration_ms</code> 为 <code>0</code> 表示时长未知，不表示曲目时长为零或播放出错。</li></ul><h3 id="_5-7-兼容字段定位" tabindex="-1">5.7 兼容字段定位 <a class="header-anchor" href="#_5-7-兼容字段定位" aria-label="Permalink to &quot;5.7 兼容字段定位&quot;">​</a></h3><p>当前实现中存在以下旧字段，其正式语义如下：</p><table tabindex="0"><thead><tr><th>旧字段</th><th>正式语义</th><th>兼容投影关系</th></tr></thead><tbody><tr><td><code>cur_music</code></td><td>对应 <code>track.title</code></td><td>若旧字段继续出现，仅视为 <code>track.title</code> 的兼容投影输出，不再作为新实现的主依据</td></tr><tr><td><code>is_playing</code></td><td>对应 <code>transport_state == &quot;playing&quot;</code></td><td>若旧字段继续出现，仅视为 <code>transport_state</code> 的布尔兼容投影，不再作为新实现的主依据</td></tr><tr><td><code>offset</code></td><td>对应 <code>position_ms / 1000</code>（秒）</td><td>若旧字段继续出现，仅视为 <code>position_ms</code> 的秒级兼容投影</td></tr><tr><td><code>duration</code></td><td>对应 <code>duration_ms / 1000</code>（秒）</td><td>若旧字段继续出现，仅视为 <code>duration_ms</code> 的秒级兼容投影</td></tr></tbody></table><p>以上旧字段如果继续存在于响应中，只能视为向后兼容的投影字段，不得作为新实现、新前端逻辑或新验收用例的主依据。新代码必须依赖本规范定义的正式字段。</p><hr><h2 id="_6-revision-规范" tabindex="-1">6. revision 规范 <a class="header-anchor" href="#_6-revision-规范" aria-label="Permalink to &quot;6. revision 规范&quot;">​</a></h2><h3 id="_6-1-定义" tabindex="-1">6.1 定义 <a class="header-anchor" href="#_6-1-定义" aria-label="Permalink to &quot;6.1 定义&quot;">​</a></h3><p><code>revision</code> 是单设备维度、单调递增的状态版本号，类型为非负整数。</p><h3 id="_6-2-递增触发条件" tabindex="-1">6.2 递增触发条件 <a class="header-anchor" href="#_6-2-递增触发条件" aria-label="Permalink to &quot;6.2 递增触发条件&quot;">​</a></h3><p>任何会导致前端可见播放状态发生变化的事件，都必须触发 <code>revision</code> 前进。这包括但不限于：</p><ul><li>播放新曲目（无论来源）</li><li>曲目自动切换（下一首、上一首）</li><li>暂停、恢复</li><li>停止</li><li>播放器进入或退出错误状态</li><li>曲目切换过程中的 <code>transport_state</code> 变化（如从 <code>playing</code> 变为 <code>switching</code>）</li></ul><p>以下操作不触发 <code>revision</code> 前进：</p><ul><li>进度位置的自然推进（前端通过插值处理，服务端不为每秒进度变化递增 revision）</li><li>不影响播放状态的内部操作（如日志记录、缓存刷新）</li></ul><h3 id="_6-3-消费约束" tabindex="-1">6.3 消费约束 <a class="header-anchor" href="#_6-3-消费约束" aria-label="Permalink to &quot;6.3 消费约束&quot;">​</a></h3><ul><li>前端只接受 <code>revision</code> 大于或等于当前已知 revision 的状态。</li><li>若收到的状态快照 <code>revision</code> 严格小于当前 UI 已渲染的 revision，该快照必须被丢弃，不得写回 UI。</li><li>多路并发请求（如同时发起的轮询请求）响应到达时，消费方必须以 <code>revision</code> 最大的那一份为准，其余丢弃。</li><li>页面刷新恢复时，前端不得用本地缓存状态覆盖服务端返回的状态，即便服务端状态的 <code>revision</code> 较小（例如服务端重启后 revision 重置），也应以服务端状态为准。</li></ul><hr><h2 id="_7-play-session-id-规范" tabindex="-1">7. play_session_id 规范 <a class="header-anchor" href="#_7-play-session-id-规范" aria-label="Permalink to &quot;7. play_session_id 规范&quot;">​</a></h2><h3 id="_7-1-定义" tabindex="-1">7.1 定义 <a class="header-anchor" href="#_7-1-定义" aria-label="Permalink to &quot;7.1 定义&quot;">​</a></h3><p><code>play_session_id</code> 是标识一次连续播放会话的唯一字符串。其作用是让消费方能够明确区分&quot;同一首歌的暂停恢复&quot;与&quot;切到了另一首歌&quot;。</p><h3 id="_7-2-切换触发条件" tabindex="-1">7.2 切换触发条件 <a class="header-anchor" href="#_7-2-切换触发条件" aria-label="Permalink to &quot;7.2 切换触发条件&quot;">​</a></h3><p>以下情况必须生成新的 <code>play_session_id</code>：</p><ul><li>切到不同曲目（无论是用户手动切换还是自动切歌）</li><li>从当前歌曲切到另一首同名歌曲</li><li>停止后重新播放任意曲目</li><li>通过 <code>POST /api/v1/play</code> 重新指定播放目标（即使目标与当前曲目相同，也视为新会话）</li></ul><p>以下情况不得生成新的 <code>play_session_id</code>：</p><ul><li>对当前曲目执行暂停</li><li>对当前暂停曲目执行恢复</li><li>仅调整音量</li></ul><h3 id="_7-3-消费约束" tabindex="-1">7.3 消费约束 <a class="header-anchor" href="#_7-3-消费约束" aria-label="Permalink to &quot;7.3 消费约束&quot;">​</a></h3><p>前端必须将以下行为绑定到 <code>play_session_id</code> 边界：</p><ul><li><strong>展示标题的切换</strong>：标题切换动画、歌名更新，必须以 <code>play_session_id</code> 变化为触发，而不是以 <code>cur_music</code> 字符串变化为触发。</li><li><strong>进度条清零</strong>：新会话开始时，进度条必须重置，不得延续上一会话的进度。</li><li><strong>歌单选中项同步</strong>：当前选中歌曲的高亮与定位，必须以 <code>play_session_id</code> + <code>track.id</code> 为依据，而不是以标题文本匹配为依据。</li><li><strong>切歌确认</strong>：前端等待切歌完成时，切歌成功的判据是收到 <code>play_session_id</code> 发生变化且 <code>transport_state</code> 变为 <code>playing</code> 的状态快照，而不是超时后猜测。</li></ul><hr><h2 id="_8-transport-state-规范" tabindex="-1">8. transport_state 规范 <a class="header-anchor" href="#_8-transport-state-规范" aria-label="Permalink to &quot;8. transport_state 规范&quot;">​</a></h2><h3 id="_8-1-正式枚举值" tabindex="-1">8.1 正式枚举值 <a class="header-anchor" href="#_8-1-正式枚举值" aria-label="Permalink to &quot;8.1 正式枚举值&quot;">​</a></h3><p><code>transport_state</code> 必须属于以下有限枚举集合：</p><table tabindex="0"><thead><tr><th>枚举值</th><th>语义</th></tr></thead><tbody><tr><td><code>idle</code></td><td>播放器未被使用，无曲目、无进度</td></tr><tr><td><code>starting</code></td><td>正在启动播放（首次解析、准备流、下发命令中），尚未确认设备侧开始播放</td></tr><tr><td><code>switching</code></td><td>正在从当前曲目切换到下一曲目，过渡期间</td></tr><tr><td><code>playing</code></td><td>设备侧已确认正在播放</td></tr><tr><td><code>paused</code></td><td>设备侧已确认处于暂停状态</td></tr><tr><td><code>stopped</code></td><td>设备侧已确认停止</td></tr><tr><td><code>error</code></td><td>播放器进入明确的异常状态，不可自动恢复</td></tr></tbody></table><h3 id="_8-2-各状态语义约束" tabindex="-1">8.2 各状态语义约束 <a class="header-anchor" href="#_8-2-各状态语义约束" aria-label="Permalink to &quot;8.2 各状态语义约束&quot;">​</a></h3><p><strong><code>idle</code></strong>：</p><ul><li>播放器未被激活，<code>track</code> 应为 <code>null</code>，<code>position_ms</code> 为 <code>0</code>。</li><li>与 <code>stopped</code> 的区别：<code>stopped</code> 表示曾经在播放但已明确停止；<code>idle</code> 表示从未开始或已完全归零。</li></ul><p><strong><code>starting</code></strong>：</p><ul><li>播放命令已下发，但尚未从设备侧得到确认播放开始的反馈。</li><li><code>track</code> 可以携带即将播放的曲目信息（如已解析到），也可以为 <code>null</code>。</li><li>不得通过清空 <code>track.title</code> 来表达&quot;正在准备&quot;的语义；应直接使用 <code>starting</code> 状态。</li></ul><p><strong><code>switching</code></strong>：</p><ul><li>正在从一首曲目切换到另一首，处于两首之间的过渡期。</li><li>不得通过 <code>track</code> 置空或返回空标题来表达&quot;切歌中&quot;。切歌中的语义必须由 <code>switching</code> 承载。</li><li>消费方收到 <code>switching</code> 状态时，应保留上一首曲目的展示状态（如标题、专辑封面），而不是清空显示。</li></ul><p><strong><code>playing</code></strong>：</p><ul><li>设备侧已确认当前正在播放，<code>track</code> 必须非空，<code>track.id</code> 必须稳定。</li><li><code>position_ms</code> 反映观测到的播放位置。</li></ul><p><strong><code>paused</code></strong>：</p><ul><li>设备侧已确认当前处于暂停状态，<code>track</code> 必须非空，<code>track.id</code> 必须与暂停前保持一致。</li><li><code>position_ms</code> 应保持在暂停时刻的观测值，不再推进。</li></ul><p><strong><code>stopped</code></strong>：</p><ul><li>播放已明确停止。<code>track</code> 可以保留最后播放曲目信息，也可以为 <code>null</code>，具体由实现决定并保持一致。</li><li><code>position_ms</code> 应为 <code>0</code> 或暂不定义。</li></ul><p><strong><code>error</code></strong>：</p><ul><li>播放器进入明确异常状态（例如解析失败、设备不可达且已超过重试上限）。</li><li><code>error</code> 状态不用于表达&quot;数据暂时缺失&quot;或&quot;切歌中间态&quot;。这两种情况分别由 <code>track.title</code> 为空与 <code>switching</code> 状态承载。</li><li>进入 <code>error</code> 后，消费方应向用户呈现明确的错误提示，而不是继续轮询等待状态自动恢复。</li></ul><h3 id="_8-3-禁止用隐式方式表达传输状态" tabindex="-1">8.3 禁止用隐式方式表达传输状态 <a class="header-anchor" href="#_8-3-禁止用隐式方式表达传输状态" aria-label="Permalink to &quot;8.3 禁止用隐式方式表达传输状态&quot;">​</a></h3><p>以下隐式表达方式不得再使用：</p><ul><li>通过 <code>track.title</code> 为空表达&quot;切歌中&quot;</li><li>通过 <code>is_playing: false</code> 且 <code>cur_music</code> 变化表达&quot;正在切歌&quot;</li><li>通过 <code>offset</code> 为 <code>0</code> 且 <code>duration</code> 不变表达&quot;正在启动&quot;</li></ul><p>所有传输状态的语义必须由 <code>transport_state</code> 字段显式承载。</p><hr><h2 id="_9-track-identity-规范" tabindex="-1">9. track identity 规范 <a class="header-anchor" href="#_9-track-identity-规范" aria-label="Permalink to &quot;9. track identity 规范&quot;">​</a></h2><h3 id="_9-1-track-id-的定义" tabindex="-1">9.1 track.id 的定义 <a class="header-anchor" href="#_9-1-track-id-的定义" aria-label="Permalink to &quot;9.1 track.id 的定义&quot;">​</a></h3><p><code>track.id</code> 是当前曲目在 XiaoMusic 系统内的稳定身份标识。其定义如下：</p><ul><li>同一首曲目在同一次连续播放会话内，<code>track.id</code> 必须保持不变。</li><li>切换到不同曲目后，<code>track.id</code> 必须发生变化。</li><li>同名歌曲（<code>track.title</code> 相同）出现在不同位置时，<code>track.id</code> 必须能够区分它们，不得相同。</li></ul><h3 id="_9-2-track-id-的生成规则" tabindex="-1">9.2 track.id 的生成规则 <a class="header-anchor" href="#_9-2-track-id-的生成规则" aria-label="Permalink to &quot;9.2 track.id 的生成规则&quot;">​</a></h3><p>当上游来源（本地库、Jellyfin 等）提供天然稳定 ID 时，应直接使用上游 ID 作为 <code>track.id</code>。</p><p>当上游来源不提供天然稳定 ID 时，系统必须生成稳定的投影 ID。投影 ID 必须满足：</p><ul><li>基于 <code>context.id</code>（若存在）+ <code>context.current_index</code>（若存在）+ <code>track.title</code> 的组合生成。</li><li>采用确定性哈希算法，保证相同输入始终产生相同输出。</li><li>若 <code>context</code> 为 <code>null</code>（直接播放单 URL），则基于 <code>track.title</code> + <code>stream_url</code> 的组合生成。</li></ul><p>禁止将 <code>track.title</code> 直接用作 <code>track.id</code>，即便在没有上下文的情况下也不允许。标题不具备唯一性，不得充当身份标识。</p><h3 id="_9-3-消费约束" tabindex="-1">9.3 消费约束 <a class="header-anchor" href="#_9-3-消费约束" aria-label="Permalink to &quot;9.3 消费约束&quot;">​</a></h3><ul><li>前端的歌曲选中同步、切歌确认、进度条绑定，必须优先依赖 <code>track.id</code>，而不是 <code>track.title</code>。</li><li>歌单列表的高亮选中逻辑，必须通过 <code>track.id</code> 与列表项 ID 对照完成，不得依赖 <code>cur_music</code> 字符串与列表项名称的文本匹配。</li><li>若 <code>track.id</code> 未发生变化但 <code>track.title</code> 发生了变化（例如标题延迟到达），消费方应更新展示标题，但不应将其视为曲目切换事件。</li></ul><hr><h2 id="_10-上下文与进度字段规范" tabindex="-1">10. 上下文与进度字段规范 <a class="header-anchor" href="#_10-上下文与进度字段规范" aria-label="Permalink to &quot;10. 上下文与进度字段规范&quot;">​</a></h2><h3 id="_10-1-上下文字段语义" tabindex="-1">10.1 上下文字段语义 <a class="header-anchor" href="#_10-1-上下文字段语义" aria-label="Permalink to &quot;10.1 上下文字段语义&quot;">​</a></h3><p><code>context.id</code> 是播放上下文的稳定标识，用于：</p><ul><li>判断播放上下文是否发生切换（例如从歌单 A 切到歌单 B）。</li><li>结合 <code>context.current_index</code> 定位当前曲目在上下文中的位置。</li></ul><p><code>context.name</code> 仅用于展示，不得用于逻辑判断。</p><p><code>context.current_index</code> 反映当前曲目在上下文中的位置索引（从 0 开始）。消费方可将其用于：</p><ul><li>歌单列表当前播放项的高亮定位（配合 <code>track.id</code>）。</li><li>判断当前是否有上下文内的下一首或上一首。</li></ul><p><code>context.current_index</code> 为 <code>null</code> 时，表示当前曲目的上下文位置无法确定（例如随机模式下未跟踪索引）。消费方不得将 <code>null</code> 视为错误，应将其作为合法状态处理。</p><h3 id="_10-2-进度字段精度与单位" tabindex="-1">10.2 进度字段精度与单位 <a class="header-anchor" href="#_10-2-进度字段精度与单位" aria-label="Permalink to &quot;10.2 进度字段精度与单位&quot;">​</a></h3><p><code>position_ms</code> 与 <code>duration_ms</code> 的单位为毫秒。</p><p>当前实现中 <code>offset</code> 与 <code>duration</code> 的单位为秒。兼容过渡期内，如果旧字段继续存在，消费方必须注意单位差异，不得混用。新实现一律以毫秒字段为准。</p><h3 id="_10-3-进度插值边界" tabindex="-1">10.3 进度插值边界 <a class="header-anchor" href="#_10-3-进度插值边界" aria-label="Permalink to &quot;10.3 进度插值边界&quot;">​</a></h3><p>前端允许在 <code>snapshot_at_ms</code> 基础上，使用本地时钟对 <code>position_ms</code> 做线性插值，使进度条展示更平滑。插值规则如下：</p><ul><li>仅在 <code>transport_state == &quot;playing&quot;</code> 时允许做正向插值。</li><li><code>transport_state</code> 为 <code>paused</code>、<code>switching</code>、<code>starting</code>、<code>stopped</code>、<code>idle</code>、<code>error</code> 时，不得推进进度。</li><li>插值时长不得超过两次状态快照之间的合理间隔（建议不超过 5 秒）；超出后应停止推进，等待下一次快照。</li><li>收到新快照后，无论插值结果如何，必须立即以新快照的 <code>position_ms</code> 为准。</li></ul><hr><h2 id="_11-统一状态投影约束" tabindex="-1">11. 统一状态投影约束 <a class="header-anchor" href="#_11-统一状态投影约束" aria-label="Permalink to &quot;11. 统一状态投影约束&quot;">​</a></h2><p>本节定义&quot;统一状态快照构建器&quot;的硬约束。这是本规范最核心的实现约束。</p><h3 id="_11-1-唯一快照构建器" tabindex="-1">11.1 唯一快照构建器 <a class="header-anchor" href="#_11-1-唯一快照构建器" aria-label="Permalink to &quot;11.1 唯一快照构建器&quot;">​</a></h3><p>系统必须存在且只存在一个状态快照构建器（State Projection Builder），负责生成符合本规范的状态快照对象。</p><p>以下各输出路径必须共享同一个快照构建器：</p><ul><li><code>GET /api/v1/player/state</code> 的 <code>data</code> 字段内容</li><li>未来 <code>GET /api/v1/player/stream</code> SSE 事件的 <code>data</code> 字段内容</li><li>任何其他对外暴露播放器状态的输出路径</li></ul><h3 id="_11-2-禁止各路径独立拼装状态" tabindex="-1">11.2 禁止各路径独立拼装状态 <a class="header-anchor" href="#_11-2-禁止各路径独立拼装状态" aria-label="Permalink to &quot;11.2 禁止各路径独立拼装状态&quot;">​</a></h3><p>以下行为不得存在：</p><ul><li>HTTP 查询接口自行从设备对象读取字段拼装状态</li><li>SSE 推送路径另行订阅设备事件并独立拼装状态</li><li>WebUI 前端通过本地逻辑&quot;补全&quot;后端未返回的字段，并将补全结果作为播放真相</li></ul><h3 id="_11-3-快照构建器的职责边界" tabindex="-1">11.3 快照构建器的职责边界 <a class="header-anchor" href="#_11-3-快照构建器的职责边界" aria-label="Permalink to &quot;11.3 快照构建器的职责边界&quot;">​</a></h3><p>状态快照构建器的职责包括：</p><ul><li>从 PlaybackCoordinator 或等效的权威内部状态获取原始播放事实</li><li>生成或查找 <code>revision</code>、<code>play_session_id</code>、<code>track.id</code> 等身份字段</li><li>将内部状态映射到本规范定义的 <code>transport_state</code> 枚举</li><li>输出符合本规范字段模型的状态快照对象</li></ul><p>状态快照构建器不得直接从设备驱动层读取原始值绕过 PlaybackCoordinator，也不得在输出路径（API 路由层或 SSE 推送层）内嵌入状态拼装逻辑。</p><hr><h2 id="_12-前端消费边界" tabindex="-1">12. 前端消费边界 <a class="header-anchor" href="#_12-前端消费边界" aria-label="Permalink to &quot;12. 前端消费边界&quot;">​</a></h2><h3 id="_12-1-前端是状态消费者-不是状态裁决者" tabindex="-1">12.1 前端是状态消费者，不是状态裁决者 <a class="header-anchor" href="#_12-1-前端是状态消费者-不是状态裁决者" aria-label="Permalink to &quot;12.1 前端是状态消费者，不是状态裁决者&quot;">​</a></h3><p>前端的职责是忠实呈现服务端状态快照，而不是对状态做重新裁决或补充定义。以下行为明确禁止：</p><ul><li>前端自行维护一套&quot;本地认定的当前歌曲&quot;，与服务端快照并列，并在冲突时选择本地版本。</li><li>前端通过 <code>rememberedPlayingSong</code>、<code>pendingTitle</code>、<code>boundaryGuess</code> 等本地机制覆盖服务端返回的 <code>track.id</code> 或 <code>track.title</code>。</li><li>前端认为服务端状态&quot;不够准确&quot;，并以本地轮询结果替代服务端状态作为展示依据。</li></ul><h3 id="_12-2-本地容错机制的合法边界" tabindex="-1">12.2 本地容错机制的合法边界 <a class="header-anchor" href="#_12-2-本地容错机制的合法边界" aria-label="Permalink to &quot;12.2 本地容错机制的合法边界&quot;">​</a></h3><p>前端可以维护以下有限的本地容错机制：</p><ul><li><strong>短时进度插值</strong>：在两次快照之间，对 <code>position_ms</code> 做线性插值以平滑进度条，但插值结果不得写回或上报为真实状态（见第 10.3 节）。</li><li><strong>页面刷新过渡展示</strong>：在页面刷新后、首次快照到达前，可短暂展示上次已知状态，用于避免白屏。此过渡期不得超过第一次有效快照到达后延续，收到快照后必须立即以快照为准。</li><li><strong>切歌动画缓冲</strong>：在收到 <code>switching</code> 状态时，可在 UI 上保持上一首曲目的展示信息，直到收到 <code>play_session_id</code> 变化且 <code>transport_state</code> 为 <code>playing</code> 的新快照。</li></ul><p>以上容错机制仅允许在服务端状态尚未到达的空窗期临时生效，收到有效快照后必须立即让位。</p><h3 id="_12-3-状态同步的优先依据" tabindex="-1">12.3 状态同步的优先依据 <a class="header-anchor" href="#_12-3-状态同步的优先依据" aria-label="Permalink to &quot;12.3 状态同步的优先依据&quot;">​</a></h3><p>前端进行以下操作时，必须以指定字段为优先依据：</p><table tabindex="0"><thead><tr><th>操作</th><th>优先依据</th></tr></thead><tbody><tr><td>判断当前播放的是哪首曲目</td><td><code>play_session_id</code> + <code>track.id</code></td></tr><tr><td>高亮歌单中当前播放项</td><td><code>track.id</code> 与列表项 ID 的对照</td></tr><tr><td>判断切歌是否已完成</td><td><code>play_session_id</code> 变化且 <code>transport_state == &quot;playing&quot;</code></td></tr><tr><td>更新进度条初始值</td><td><code>position_ms</code>（以 <code>snapshot_at_ms</code> 为观测基准）</td></tr><tr><td>判断是否正在切歌</td><td><code>transport_state == &quot;switching&quot;</code></td></tr><tr><td>判断是否处于暂停</td><td><code>transport_state == &quot;paused&quot;</code></td></tr><tr><td>判断播放器是否出错</td><td><code>transport_state == &quot;error&quot;</code></td></tr><tr><td>丢弃过期状态</td><td><code>revision</code> 比较</td></tr></tbody></table><hr><h2 id="_13-错误与缺省处理原则" tabindex="-1">13. 错误与缺省处理原则 <a class="header-anchor" href="#_13-错误与缺省处理原则" aria-label="Permalink to &quot;13. 错误与缺省处理原则&quot;">​</a></h2><h3 id="_13-1-数据暂缺、切歌中、真正异常-三者必须明确区分" tabindex="-1">13.1 数据暂缺、切歌中、真正异常，三者必须明确区分 <a class="header-anchor" href="#_13-1-数据暂缺、切歌中、真正异常-三者必须明确区分" aria-label="Permalink to &quot;13.1 数据暂缺、切歌中、真正异常，三者必须明确区分&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情况</th><th>正确表达方式</th><th>禁止的表达方式</th></tr></thead><tbody><tr><td>标题信息尚未解析完成</td><td><code>track.title</code> 为空字符串，<code>track.id</code> 保持稳定，<code>transport_state</code> 为 <code>playing</code> 或 <code>starting</code></td><td>将 <code>transport_state</code> 设为 <code>error</code>；消费方将其展示为&quot;未知歌曲&quot;</td></tr><tr><td>正在切换到下一首</td><td><code>transport_state == &quot;switching&quot;</code></td><td>清空 <code>track</code>；将 <code>is_playing</code> 设为 <code>false</code>；通过 <code>cur_music</code> 为空表达</td></tr><tr><td>播放器进入真正异常</td><td><code>transport_state == &quot;error&quot;</code></td><td>无</td></tr></tbody></table><h3 id="_13-2-metadata-未完全解析时的处理" tabindex="-1">13.2 metadata 未完全解析时的处理 <a class="header-anchor" href="#_13-2-metadata-未完全解析时的处理" aria-label="Permalink to &quot;13.2 metadata 未完全解析时的处理&quot;">​</a></h3><p>当曲目 metadata（如标题、时长）尚未完全解析时：</p><ul><li><code>track.id</code> 必须保持稳定，不得因 metadata 缺失而生成新的 <code>play_session_id</code>。</li><li><code>track.title</code> 可以为空字符串，但不得为 <code>null</code>（若 <code>track</code> 对象本身非空）。</li><li><code>duration_ms</code> 未知时应为 <code>0</code>，消费方收到 <code>duration_ms == 0</code> 时不得将其理解为&quot;播放出错&quot;。</li><li>消费方不得因为 <code>track.title</code> 为空而回退显示上一首曲目的标题，或跳到下一首。</li></ul><h3 id="_13-3-禁止因中间态拼装导致的状态回退" tabindex="-1">13.3 禁止因中间态拼装导致的状态回退 <a class="header-anchor" href="#_13-3-禁止因中间态拼装导致的状态回退" aria-label="Permalink to &quot;13.3 禁止因中间态拼装导致的状态回退&quot;">​</a></h3><p>以下行为明确禁止：</p><ul><li>因 <code>transport_state</code> 处于 <code>switching</code> 或 <code>starting</code> 而导致 UI 回退到显示上一首（除非这是设计明确要求的过渡动效）。</li><li>因服务端快照某字段暂缺而触发前端&quot;推测下一首&quot;逻辑，主动将 UI 切换到顺序下一首。</li><li>在 <code>revision</code> 未变化的情况下，因多次重复轮询收到同一快照而触发不必要的 UI 重渲染。</li></ul><h3 id="_13-4-旧状态不得回写" tabindex="-1">13.4 旧状态不得回写 <a class="header-anchor" href="#_13-4-旧状态不得回写" aria-label="Permalink to &quot;13.4 旧状态不得回写&quot;">​</a></h3><p>前端在以下情况下必须主动丢弃旧状态，不得将其回写 UI：</p><ul><li>收到的快照 <code>revision</code> 小于当前已渲染状态的 <code>revision</code>。</li><li>页面可见性恢复（从后台切回前台）后，收到服务端快照前不得将 localStorage / sessionStorage 中的旧状态写入展示层。</li></ul><hr><h2 id="_14-与其他规范的关系" tabindex="-1">14. 与其他规范的关系 <a class="header-anchor" href="#_14-与其他规范的关系" aria-label="Permalink to &quot;14. 与其他规范的关系&quot;">​</a></h2><p>本节说明本文档在整体文档体系中的定位，以及与相关规范的上下位关系。</p><h3 id="_14-1-本文档是上位状态语义规范" tabindex="-1">14.1 本文档是上位状态语义规范 <a class="header-anchor" href="#_14-1-本文档是上位状态语义规范" aria-label="Permalink to &quot;14.1 本文档是上位状态语义规范&quot;">​</a></h3><p>本文档定义&quot;权威播放状态快照&quot;的结构、字段语义与消费约束，是以下所有文档的共同上位规范。当下位文档与本文档存在冲突时，以本文档为准。</p><h3 id="_14-2-与-docs-api-api-v1-spec-md-的关系" tabindex="-1">14.2 与 <code>docs/api/api_v1_spec.md</code> 的关系 <a class="header-anchor" href="#_14-2-与-docs-api-api-v1-spec-md-的关系" aria-label="Permalink to &quot;14.2 与 `docs/api/api_v1_spec.md` 的关系&quot;">​</a></h3><p><code>docs/api/api_v1_spec.md</code> 是 XiaoMusic Runtime v1 API 的唯一权威契约来源，承接本文档的状态语义，定义 <code>GET /api/v1/player/state</code> 的具体 HTTP 接口契约，包括请求参数、响应 envelope 结构、错误模型与兼容字段处理。</p><p>本文档与 <code>api_v1_spec.md</code> 的分工：本文档定义&quot;快照应该包含什么语义&quot;，<code>api_v1_spec.md</code> 定义&quot;快照如何通过 HTTP 对外暴露&quot;。</p><h3 id="_14-3-与-docs-spec-player-stream-sse-spec-md-的关系" tabindex="-1">14.3 与 <code>docs/spec/player_stream_sse_spec.md</code> 的关系 <a class="header-anchor" href="#_14-3-与-docs-spec-player-stream-sse-spec-md-的关系" aria-label="Permalink to &quot;14.3 与 `docs/spec/player_stream_sse_spec.md` 的关系&quot;">​</a></h3><p>当 <code>docs/spec/player_stream_sse_spec.md</code> 建立后，该文档承接本文档的状态语义，定义 SSE 事件的传输协议、连接管理、心跳机制与断线重连约束。SSE 事件中的状态数据字段，必须与本文档定义的状态快照模型保持完全一致。</p><h3 id="_14-4-与-webui-相关规范的关系" tabindex="-1">14.4 与 WebUI 相关规范的关系 <a class="header-anchor" href="#_14-4-与-webui-相关规范的关系" aria-label="Permalink to &quot;14.4 与 WebUI 相关规范的关系&quot;">​</a></h3><p><code>docs/spec/webui_playback_state_machine_spec.md</code> 与 <code>docs/spec/webui_playback_state_machine_mapping.md</code> 定义 WebUI 的前端展示状态机与实现映射。这些文档定义前端如何消费本文档所描述的状态快照，但不得在前端侧重新定义播放真相的来源。前端规范中凡涉及&quot;以哪个字段为权威依据&quot;的判断，必须与本文档第 12.3 节保持一致。</p><h3 id="_14-5-与-docs-spec-playback-coordinator-interface-md-的关系" tabindex="-1">14.5 与 <code>docs/spec/playback_coordinator_interface.md</code> 的关系 <a class="header-anchor" href="#_14-5-与-docs-spec-playback-coordinator-interface-md-的关系" aria-label="Permalink to &quot;14.5 与 `docs/spec/playback_coordinator_interface.md` 的关系&quot;">​</a></h3><p><code>docs/spec/playback_coordinator_interface.md</code> 定义 PlaybackCoordinator 的内部接口契约、Adapter 职责与 Framework 职责。PlaybackCoordinator 是状态快照构建器的内部状态来源；其对外暴露的播放事实（<code>current_index</code>、<code>context</code>、<code>track</code> 等）必须通过本文档定义的统一快照构建器转化为对外输出，不得直接绕过快照构建器暴露原始内部状态。</p><h3 id="_14-6-与-docs-spec-runtime-specification-md-的关系" tabindex="-1">14.6 与 <code>docs/spec/runtime_specification.md</code> 的关系 <a class="header-anchor" href="#_14-6-与-docs-spec-runtime-specification-md-的关系" aria-label="Permalink to &quot;14.6 与 `docs/spec/runtime_specification.md` 的关系&quot;">​</a></h3><p><code>docs/spec/runtime_specification.md</code> 定义 <code>xiaomusic/core/</code> 的数据模型、接口契约与错误体系。其中 <code>ResolvedMedia</code>、<code>TransportDispatchResult</code> 等内部数据模型是构建状态快照的原始输入来源，但其字段不得直接透传为对外状态快照字段；必须经过状态快照构建器的规范化映射。</p>',194)]))}const _=t(c,[["render",i]]);export{u as __pageData,_ as default};
